TARGET_FUNCTIONS = ['home', 'fb_page', 'render_dashboard_page', 'show_grouped_table', 'show_hierarchy', 'show_dashboard']

MODULE_SOURCE = 'def home(request: Request):\n    if request.method == "HEAD":\n        return Response(status_code=200)\n    return RedirectResponse(url="/dashboard" if get_current_user(request) else "/login", status_code=302)\n\ndef fb_page(request: Request):\n    user = get_current_user(request)\n    if not user:\n        return auth_redirect_response()\n    enforce_page_access(user, "fb")\n\n    content = """\n    <div class="panel compact-panel">\n        <div class="empty-dev" style="min-height:34vh;">\n            <div class="empty-dev-card">\n                <div class="big">FB</div>\n                <div class="muted">This section is empty for now.</div>\n            </div>\n        </div>\n    </div>\n    """\n    return page_shell("FB", content, active_page="fb", current_user=user)\n\ndef show_grouped_table(\n    request: Request,\n    buyer: str = Query(default=""),\n    brand: str = Query(default=""),\n    manager: str = Query(default=""),\n    geo: str = Query(default=""),\n    ad_name: str = Query(default=""),\n    adset_name: str = Query(default=""),\n    creative: str = Query(default=""),\n    search: str = Query(default=""),\n    period_view: str = Query(default="current"),\n    period_label: str = Query(default=""),\n    source_name: str = Query(default=""),\n    sort_by: str = Query(default="spend"),\n    order: str = Query(default="desc"),\n):\n    user = get_current_user(request)\n    if not user:\n        return auth_redirect_response()\n    enforce_page_access(user, "grouped")\n    ensure_fb_table()\n    buyer = resolve_effective_buyer(user, buyer)\n    period_view = safe_text(period_view) or "current"\n    period_label = safe_text(period_label)\n    source_name = safe_text(source_name)\n    effective_period_label = resolve_period_label(period_view, period_label) or get_current_period_label()\n    if source_name:\n        matching_upload = get_latest_fb_upload_summary(source_name=source_name)\n        if matching_upload and (\n            (buyer and safe_text(matching_upload.get("buyer")) != safe_text(buyer))\n            or safe_text(matching_upload.get("period_label")) != safe_text(effective_period_label)\n        ):\n            source_name = ""\n    data = get_filtered_data(\n        buyer,\n        manager,\n        geo,\n        brand,\n        search,\n        effective_period_label,\n        source_name,\n        ad_name=ad_name,\n        adset_name=adset_name,\n        creative=creative,\n    )\n    rows = aggregate_grouped_rows(data)\n    scope_rows = get_filtered_data(\n        buyer=buyer,\n        period_label=effective_period_label,\n        source_name=source_name,\n    )\n    brand_scope_rows = get_filtered_data(\n        buyer=buyer,\n        period_label=effective_period_label,\n        source_name=source_name,\n        manager=manager,\n        geo=geo,\n        ad_name=ad_name,\n        adset_name=adset_name,\n        creative=creative,\n        search=search,\n    )\n    manager_scope_rows = get_filtered_data(\n        buyer=buyer,\n        period_label=effective_period_label,\n        source_name=source_name,\n        offer=brand,\n        geo=geo,\n        ad_name=ad_name,\n        adset_name=adset_name,\n        creative=creative,\n        search=search,\n    )\n    geo_scope_rows = get_filtered_data(\n        buyer=buyer,\n        period_label=effective_period_label,\n        source_name=source_name,\n        offer=brand,\n        manager=manager,\n        ad_name=ad_name,\n        adset_name=adset_name,\n        creative=creative,\n        search=search,\n    )\n    ad_scope_rows = get_filtered_data(\n        buyer=buyer,\n        period_label=effective_period_label,\n        source_name=source_name,\n        offer=brand,\n        manager=manager,\n        geo=geo,\n        creative=creative,\n        search=search,\n    )\n    adset_scope_rows = get_filtered_data(\n        buyer=buyer,\n        period_label=effective_period_label,\n        source_name=source_name,\n        offer=brand,\n        manager=manager,\n        geo=geo,\n        ad_name=ad_name,\n        creative=creative,\n        search=search,\n    )\n    creative_scope_rows = get_filtered_data(\n        buyer=buyer,\n        period_label=effective_period_label,\n        source_name=source_name,\n        offer=brand,\n        manager=manager,\n        geo=geo,\n        ad_name=ad_name,\n        adset_name=adset_name,\n        search=search,\n    )\n    period_options = make_options(build_period_options(), effective_period_label)\n    source_options = make_options(get_fb_upload_options(effective_period_label, buyer), source_name)\n    upload_summaries = [\n        item for item in get_fb_upload_summaries()\n        if safe_text(item.get("period_label")) == effective_period_label and (not buyer or safe_text(item.get("buyer")) == safe_text(buyer))\n    ]\n\n    allowed_sort_fields = {\n        "buyer", "ad_name", "material_views", "cost_per_content_view", "clicks", "cpc_real", "frequency", "ctr",\n        "leads", "cpl_real", "paid_subscriptions", "cost_per_paid_subscription", "contacts",\n        "cost_per_contact", "reg", "cost_per_completed_registration", "ftd", "cpa_real", "spend",\n        "account_id", "adset_name", "budget", "campaign_name"\n    }\n    if sort_by not in allowed_sort_fields:\n        sort_by = "spend"\n    reverse = order.lower() != "asc"\n    rows.sort(key=lambda x: x.get(sort_by, 0) if x.get(sort_by) is not None else 0, reverse=reverse)\n\n    totals = aggregate_totals(rows)\n    buyer_options = "".join(\n        f\'<option value="{escape(value)}" {"selected" if buyer == value else ""}>{escape(label)}</option>\'\n        for value, label in [("", "Все")] + get_fb_buyer_name_options()\n    ) if is_admin_role(user) or user.get("role") == "operator" else f\'<option value="{escape(buyer)}">{escape(buyer or "Мой buyer")}</option>\'\n    brand_options = make_options(sorted({safe_text(row.offer) for row in brand_scope_rows if safe_text(row.offer)}), brand)\n    manager_options = make_options(sorted({safe_text(row.manager) for row in manager_scope_rows if safe_text(row.manager)}), manager)\n    geo_options = make_options(sorted({safe_text(row.geo) for row in geo_scope_rows if safe_text(row.geo)}), geo)\n    ad_name_options = make_options(sorted({safe_text(row.ad_name) for row in ad_scope_rows if safe_text(row.ad_name)}), ad_name)\n    adset_options = make_options(sorted({safe_text(row.adset_name) for row in adset_scope_rows if safe_text(row.adset_name)}), adset_name)\n    creative_options = make_options(sorted({safe_text(row.creative) for row in creative_scope_rows if safe_text(row.creative)}), creative)\n    export_qs = build_query_string(\n        buyer=buyer,\n        brand=brand,\n        manager=manager,\n        geo=geo,\n        ad_name=ad_name,\n        adset_name=adset_name,\n        creative=creative,\n        search=search,\n        period_view=period_view,\n        period_label=effective_period_label,\n        source_name=source_name,\n        sort_by=sort_by,\n        order=order,\n    )\n    export_link = f"/export/grouped?{export_qs}" if export_qs else "/export/grouped"\n\n    table_headers = [\n        ("buyer", "Buyer"),\n        ("ad_name", "Название объявления"),\n        ("material_views", "Просмотры материалов"),\n        ("cost_per_content_view", "Цена за просмотр контента"),\n        ("clicks", "Клики по ссылке"),\n        ("cpc_real", "CPC (цена за клик по ссылке)"),\n        ("frequency", "Частота"),\n        ("ctr", "CTR (все)"),\n        ("leads", "Лиды"),\n        ("cpl_real", "Цена за лид"),\n        ("paid_subscriptions", "Подписки"),\n        ("cost_per_paid_subscription", "Цена за платную подписку"),\n        ("contacts", "Контакты"),\n        ("cost_per_contact", "Цена за контакт"),\n        ("reg", "Завершенные регистрации"),\n        ("cost_per_completed_registration", "Цена за завершенную регистрацию"),\n        ("ftd", "Покупки"),\n        ("cpa_real", "Цена за покупку"),\n        ("spend", "Сумма затрат"),\n        ("account_id", "Идентификатор аккаунта"),\n        ("adset_name", "Название группы объявлений"),\n        ("budget", "Budget"),\n        ("campaign_name", "Название компании"),\n    ]\n\n    head_html = ""\n    for field, label in table_headers:\n        head_html += f\'\'\'\n        <th data-col="{field}" draggable="true">\n            <div class="th-inner">\n                <span class="drag-handle">⋮⋮</span>\n                <span>{sort_link(label, field, sort_by, order, buyer=buyer, brand=brand, manager=manager, geo=geo, search=search, period_view=period_view, period_label=effective_period_label, source_name=source_name, ad_name=ad_name, adset_name=adset_name, creative=creative)}</span>\n            </div>\n            <span class="resizer"></span>\n        </th>\n        \'\'\'\n\n    rows_html = ""\n    for row in rows:\n        rows_html += f\'\'\'\n        <tr class="{get_row_class(row)}">\n            <td data-col="buyer">{escape(row["buyer"])}</td>\n            <td data-col="ad_name">{escape(row["ad_name"])}</td>\n            <td data-col="material_views">{format_int_or_float(row["material_views"])}</td>\n            <td data-col="cost_per_content_view">{format_money(row["cost_per_content_view"])}</td>\n            <td data-col="clicks">{format_int_or_float(row["clicks"])}</td>\n            <td data-col="cpc_real">{format_money(row["cpc_real"])}</td>\n            <td data-col="frequency">{format_int_or_float(row["frequency"])}</td>\n            <td data-col="ctr">{format_percent(row["ctr"])}</td>\n            <td data-col="leads">{format_int_or_float(row["leads"])}</td>\n            <td data-col="cpl_real">{format_money(row["cpl_real"])}</td>\n            <td data-col="paid_subscriptions">{format_int_or_float(row["paid_subscriptions"])}</td>\n            <td data-col="cost_per_paid_subscription">{format_money(row["cost_per_paid_subscription"])}</td>\n            <td data-col="contacts">{format_int_or_float(row["contacts"])}</td>\n            <td data-col="cost_per_contact">{format_money(row["cost_per_contact"])}</td>\n            <td data-col="reg">{format_int_or_float(row["reg"])}</td>\n            <td data-col="cost_per_completed_registration">{format_money(row["cost_per_completed_registration"])}</td>\n            <td data-col="ftd">{format_int_or_float(row["ftd"])}</td>\n            <td data-col="cpa_real">{format_money(row["cpa_real"])}</td>\n            <td data-col="spend">{format_money(row["spend"])}</td>\n            <td data-col="account_id">{escape(row["account_id"])}</td>\n            <td data-col="adset_name">{escape(row["adset_name"])}</td>\n            <td data-col="budget">{format_money(row["budget"])}</td>\n            <td data-col="campaign_name">{escape(row["campaign_name"])}</td>\n        </tr>\n        \'\'\'\n\n    column_chips = ""\n    for field, label in table_headers:\n        column_chips += f\'<label class="column-chip"><input type="checkbox" class="column-toggle" value="{field}" checked> {escape(label)}</label>\'\n\n    delete_upload_rows = ""\n    for item in upload_summaries:\n        delete_upload_rows += f"""\n        <tr>\n            <td>{escape(item.get(\'buyer\') or \'—\')}</td>\n            <td>{escape(item.get(\'period_label\') or \'—\')}</td>\n            <td>{escape(item.get(\'date_start\') or \'—\')}</td>\n            <td>{escape(item.get(\'date_end\') or \'—\')}</td>\n            <td>{format_int_or_float(item.get(\'rows_count\', 0))}</td>\n            <td>{format_money(item.get(\'spend\', 0))}</td>\n            <td style="white-space:nowrap;">\n                <form method="post" action="/grouped/delete-upload">\n                    <input type="hidden" name="source_name" value="{escape(item.get(\'source_name\', \'\'))}">\n                    <input type="hidden" name="period_view" value="{escape(period_view)}">\n                    <input type="hidden" name="period_label" value="{escape(effective_period_label)}">\n                    <input type="hidden" name="buyer" value="{escape(buyer)}">\n                    <input type="hidden" name="brand" value="{escape(brand)}">\n                    <input type="hidden" name="manager" value="{escape(manager)}">\n                    <input type="hidden" name="geo" value="{escape(geo)}">\n                    <input type="hidden" name="ad_name" value="{escape(ad_name)}">\n                    <input type="hidden" name="adset_name" value="{escape(adset_name)}">\n                    <input type="hidden" name="creative" value="{escape(creative)}">\n                    <input type="hidden" name="search" value="{escape(search)}">\n                    <input type="hidden" name="sort_by" value="{escape(sort_by)}">\n                    <input type="hidden" name="order" value="{escape(order)}">\n                    <button type="submit" class="ghost-btn small-btn">Delete</button>\n                </form>\n            </td>\n        </tr>\n        """\n\n    upload_filter_html = f"""\n    <form method="get" action="/grouped" class="players-upload-filter">\n        <input type="hidden" name="period_view" value="period">\n        <input type="hidden" name="period_label" value="{escape(effective_period_label)}">\n        <input type="hidden" name="buyer" value="{escape(buyer)}">\n        <input type="hidden" name="brand" value="{escape(brand)}">\n        <input type="hidden" name="manager" value="{escape(manager)}">\n        <input type="hidden" name="geo" value="{escape(geo)}">\n        <input type="hidden" name="ad_name" value="{escape(ad_name)}">\n        <input type="hidden" name="adset_name" value="{escape(adset_name)}">\n        <input type="hidden" name="creative" value="{escape(creative)}">\n        <input type="hidden" name="search" value="{escape(search)}">\n        <input type="hidden" name="sort_by" value="{escape(sort_by)}">\n        <input type="hidden" name="order" value="{escape(order)}">\n        <label>Upload<select name="source_name" onchange="this.form.submit()">{source_options}</select></label>\n    </form>\n    """\n\n    upload_buyer_options = "".join([\n        f\'<option value="{escape(value)}">{escape(label)}</option>\'\n        for value, label in get_fb_buyer_name_options()\n    ]) or \'<option value="">No users</option>\'\n\n    upload_block = ""\n    if is_admin_role(user):\n        upload_block = f\'\'\'\n        <div class="players-side-tools">\n            <div class="players-icon-stack">\n            <details class="upload-menu upload-menu-right">\n                <summary class="ghost-btn small-btn toolbar-square-icon-btn" aria-label="Delete upload" title="Delete upload">🗑</summary>\n                <div class="upload-menu-list" style="width:min(760px, calc(100vw - 48px));">\n                    <div class="panel-subtitle">Choose the exact FB upload you want to remove.</div>\n                    <div class="table-wrap" style="margin-top:8px;">\n                        <table style="min-width:680px;">\n                            <thead>\n                                <tr>\n                                    <th>Buyer</th>\n                                    <th>Period</th>\n                                    <th>From</th>\n                                    <th>To</th>\n                                    <th>Rows</th>\n                                    <th>Spend</th>\n                                    <th>Action</th>\n                                </tr>\n                            </thead>\n                            <tbody>{delete_upload_rows if delete_upload_rows else \'<tr><td colspan="7">No uploads yet</td></tr>\'}</tbody>\n                        </table>\n                    </div>\n                </div>\n            </details>\n            <details class="upload-menu upload-menu-right">\n                <summary class="btn toggle-indicator toolbar-square-trigger" aria-label="Upload FB" title="Upload FB"></summary>\n                <div class="upload-menu-list" style="width:360px; max-width:min(360px, calc(100vw - 48px));">\n                    <form method="post" action="/upload" enctype="multipart/form-data">\n                        <label>Buyer\n                            <select name="buyer" required>{upload_buyer_options}</select>\n                        </label>\n                        <label>CSV / XLSX\n                            <input type="file" name="file" accept=".csv,.xlsx,.xls" required>\n                        </label>\n                        <button type="submit" class="btn small-btn">Upload</button>\n                    </form>\n                </div>\n            </details>\n            </div>\n            {upload_filter_html}\n        </div>\n        \'\'\'\n    else:\n        upload_block = f\'<div class="players-side-tools">{upload_filter_html}</div>\'\n\n    content = f\'\'\'\n    {render_active_period_banner(effective_period_label)}\n\n    <div class="panel compact-panel">\n        <div class="toolbar-actions players-toolbar">\n            <div class="panel compact-panel filters">\n                <form method="get" action="/grouped" class="players-filter-form" data-persist-filters="grouped">\n                    {\'<label>Buyer<select name="buyer">\' + buyer_options + \'</select></label>\' if is_admin_role(user) or user.get("role") == "operator" else \'\'}\n                    <input type="hidden" name="period_view" value="period">\n                    <label>Period<select name="period_label">{period_options}</select></label>\n                    <label>Brands<select name="brand">{brand_options}</select></label>\n                    <label>Manager<select name="manager">{manager_options}</select></label>\n                    <label>Geo<select name="geo">{geo_options}</select></label>\n                    <label>Ad<select name="ad_name">{ad_name_options}</select></label>\n                    <label>Ad Group<select name="adset_name">{adset_options}</select></label>\n                    <label>Creative<select name="creative">{creative_options}</select></label>\n                    <label>Search<input type="text" name="search" value="{escape(search)}" placeholder="Search rows"></label>\n                    <input type="hidden" name="sort_by" value="{escape(sort_by)}">\n                    <input type="hidden" name="order" value="{escape(order)}">\n                    <button type="submit" class="btn small-btn">Filter</button>\n                    <a href="/grouped" class="ghost-btn small-btn" data-reset-filters="grouped">Reset</a>\n                </form>\n            </div>\n            {upload_block}\n        </div>\n    </div>\n\n    {render_stats_cards(totals)}\n\n    <div class="panel compact-panel">\n        <div class="table-wrap">\n            <table id="groupedTable">\n                <thead><tr>{head_html}</tr></thead>\n                <tbody>{rows_html if rows_html else \'<tr><td colspan="23">No data</td></tr>\'}</tbody>\n            </table>\n        </div>\n    </div>\n    \'\'\'\n\n    extra_scripts = """\n    <script>\n        const HIDDEN_KEY = window.teambeadStorageKey(\'hidden-columns-v2\');\n        const ORDER_KEY = window.teambeadStorageKey(\'column-order-v2\');\n        const WIDTH_KEY = window.teambeadStorageKey(\'column-widths-v2\');\n\n        function getTable() { return document.getElementById(\'groupedTable\'); }\n        function getHeaderRow() { return getTable()?.querySelector(\'thead tr\'); }\n        function getCurrentOrder() {\n            return Array.from(getHeaderRow().querySelectorAll(\'th[data-col]\')).map(th => th.dataset.col);\n        }\n        function getRows() {\n            return Array.from(getTable().querySelectorAll(\'tr\'));\n        }\n        function reorderCells(order) {\n            getRows().forEach(row => {\n                const cellsMap = {};\n                Array.from(row.children).forEach(cell => {\n                    const key = cell.dataset.col;\n                    if (key) cellsMap[key] = cell;\n                });\n                order.forEach(key => {\n                    if (cellsMap[key]) row.appendChild(cellsMap[key]);\n                });\n            });\n        }\n        function applyOrder() {\n            const saved = JSON.parse(localStorage.getItem(ORDER_KEY) || \'[]\');\n            const current = getCurrentOrder();\n            if (!saved.length) return;\n            const merged = saved.filter(x => current.includes(x)).concat(current.filter(x => !saved.includes(x)));\n            reorderCells(merged);\n        }\n        function applyVisibility() {\n            const hidden = JSON.parse(localStorage.getItem(HIDDEN_KEY) || \'[]\');\n            document.querySelectorAll(\'.column-toggle\').forEach(cb => {\n                cb.checked = !hidden.includes(cb.value);\n            });\n            document.querySelectorAll(\'[data-col]\').forEach(el => {\n                el.style.display = hidden.includes(el.dataset.col) ? \'none\' : \'\';\n            });\n        }\n        function saveVisibility() {\n            const hidden = [];\n            document.querySelectorAll(\'.column-toggle\').forEach(cb => {\n                if (!cb.checked) hidden.push(cb.value);\n            });\n            localStorage.setItem(HIDDEN_KEY, JSON.stringify(hidden));\n            applyVisibility();\n        }\n        function showAllColumns() {\n            localStorage.setItem(HIDDEN_KEY, JSON.stringify([]));\n            applyVisibility();\n        }\n        function resetColumnsAll() {\n            localStorage.removeItem(HIDDEN_KEY);\n            localStorage.removeItem(ORDER_KEY);\n            localStorage.removeItem(WIDTH_KEY);\n            window.location.reload();\n        }\n        function toggleColumnMenu() {\n            document.getElementById(\'columnMenu\').classList.toggle(\'open\');\n        }\n        function applyWidths() {\n            const widths = JSON.parse(localStorage.getItem(WIDTH_KEY) || \'{}\');\n            Object.entries(widths).forEach(([key, width]) => {\n                document.querySelectorAll(\'[data-col="\' + key + \'"]\').forEach(el => {\n                    el.style.width = width + \'px\';\n                    el.style.minWidth = width + \'px\';\n                    el.style.maxWidth = width + \'px\';\n                });\n            });\n        }\n        function saveWidth(key, width) {\n            const widths = JSON.parse(localStorage.getItem(WIDTH_KEY) || \'{}\');\n            widths[key] = Math.max(80, Math.round(width));\n            localStorage.setItem(WIDTH_KEY, JSON.stringify(widths));\n        }\n        function initResizers() {\n            document.querySelectorAll(\'#groupedTable th[data-col]\').forEach(th => {\n                const resizer = th.querySelector(\'.resizer\');\n                if (!resizer) return;\n                let startX = 0;\n                let startWidth = 0;\n                let resizing = false;\n                const key = th.dataset.col;\n                resizer.addEventListener(\'mousedown\', function(e) {\n                    e.preventDefault();\n                    e.stopPropagation();\n                    resizing = true;\n                    startX = e.clientX;\n                    startWidth = th.getBoundingClientRect().width;\n                    document.body.style.cursor = \'col-resize\';\n                });\n                document.addEventListener(\'mousemove\', function(e) {\n                    if (!resizing) return;\n                    const newWidth = Math.max(80, startWidth + (e.clientX - startX));\n                    document.querySelectorAll(\'[data-col="\' + key + \'"]\').forEach(el => {\n                        el.style.width = newWidth + \'px\';\n                        el.style.minWidth = newWidth + \'px\';\n                        el.style.maxWidth = newWidth + \'px\';\n                    });\n                });\n                document.addEventListener(\'mouseup\', function() {\n                    if (!resizing) return;\n                    resizing = false;\n                    document.body.style.cursor = \'\';\n                    saveWidth(key, th.getBoundingClientRect().width);\n                });\n            });\n        }\n        function initDragAndDrop() {\n            let dragged = null;\n            document.querySelectorAll(\'#groupedTable th[data-col]\').forEach(th => {\n                th.addEventListener(\'dragstart\', function(e) {\n                    if (e.target.classList.contains(\'resizer\')) { e.preventDefault(); return; }\n                    dragged = th;\n                    th.classList.add(\'dragging\');\n                });\n                th.addEventListener(\'dragend\', function() {\n                    document.querySelectorAll(\'#groupedTable th[data-col]\').forEach(x => x.classList.remove(\'dragging\', \'drag-target-left\', \'drag-target-right\'));\n                    dragged = null;\n                });\n                th.addEventListener(\'dragover\', function(e) {\n                    e.preventDefault();\n                    if (!dragged || dragged === th) return;\n                    const rect = th.getBoundingClientRect();\n                    const before = (e.clientX - rect.left) < rect.width / 2;\n                    th.classList.toggle(\'drag-target-left\', before);\n                    th.classList.toggle(\'drag-target-right\', !before);\n                });\n                th.addEventListener(\'dragleave\', function() {\n                    th.classList.remove(\'drag-target-left\', \'drag-target-right\');\n                });\n                th.addEventListener(\'drop\', function(e) {\n                    e.preventDefault();\n                    if (!dragged || dragged === th) return;\n                    const rect = th.getBoundingClientRect();\n                    const before = (e.clientX - rect.left) < rect.width / 2;\n                    if (before) th.parentNode.insertBefore(dragged, th);\n                    else th.parentNode.insertBefore(dragged, th.nextSibling);\n                    const order = getCurrentOrder();\n                    reorderCells(order);\n                    localStorage.setItem(ORDER_KEY, JSON.stringify(order));\n                    document.querySelectorAll(\'#groupedTable th[data-col]\').forEach(x => x.classList.remove(\'drag-target-left\', \'drag-target-right\'));\n                });\n            });\n        }\n        document.querySelectorAll(\'.column-toggle\').forEach(cb => cb.addEventListener(\'change\', saveVisibility));\n        applyOrder();\n        applyVisibility();\n        applyWidths();\n        initResizers();\n        initDragAndDrop();\n    </script>\n    """\n\n    top_actions = f\'<a class="small-btn" href="{export_link}">⬇ CSV</a>\' if is_admin_role(user) else ""\n    return page_shell("FB — Export", content, "grouped", extra_scripts, top_actions=top_actions, current_user=user)\n\ndef render_dashboard_page(\n    request: Request,\n    buyer: str = Query(default=""),\n    manager: str = Query(default=""),\n    geo: str = Query(default=""),\n    offer: str = Query(default=""),\n    search: str = Query(default=""),\n    period_view: str = Query(default="current"),\n    period_label: str = Query(default=""),\n):\n    user = get_current_user(request)\n    if not user:\n        return auth_redirect_response()\n    enforce_page_access(user, "hierarchy")\n    buyer = resolve_effective_buyer(user, safe_text(buyer))\n    manager = safe_text(manager)\n    geo = safe_text(geo)\n    offer = safe_text(offer)\n    search = safe_text(search)\n    period_view = safe_text(period_view) or "current"\n    period_label = safe_text(period_label)\n    effective_period_label = resolve_period_label(period_view, period_label) or get_current_period_label()\n    data = get_filtered_data(buyer, manager, geo, offer, search, period_label=effective_period_label)\n    rows = enrich_statistic_rows(aggregate_grouped_rows(data), period_label=effective_period_label)\n    all_buyers, all_managers, all_geos, all_offers = get_scoped_filter_options(user, period_label=effective_period_label)\n    period_view_options = "".join([\n        f\'<option value="{value}" {"selected" if period_view == value else ""}>{label}</option>\'\n        for value, label in [("all", "All Time"), ("current", "Current Period"), ("period", "Choose Period")]\n    ])\n    period_options = make_options(build_period_options(), effective_period_label)\n\n    buyer_options = make_options(all_buyers, buyer) if is_admin_role(user) or user.get("role") == "operator" else f\'<option value="{escape(buyer)}">{escape(buyer or "Мой buyer")}</option>\'\n    manager_options = make_options(all_managers, manager)\n    geo_options = make_options(all_geos, geo)\n    offer_options = make_options(all_offers, offer)\n    totals = aggregate_totals(rows)\n    overview = build_dashboard_overview(\n        user,\n        rows,\n        buyer=buyer,\n        manager=manager,\n        geo=geo,\n        offer=offer,\n        search=search,\n        period_label=effective_period_label,\n    )\n\n    export_qs = build_query_string(buyer=buyer, manager=manager, geo=geo, offer=offer, search=search, period_view=period_view, period_label=effective_period_label)\n    export_link = f"/export/hierarchy?{export_qs}" if export_qs else "/export/hierarchy"\n\n    content = f\'\'\'\n    {render_active_period_banner(effective_period_label)}\n\n    <div class="panel compact-panel">\n        <div class="toolbar-actions">\n            <div class="panel compact-panel filters">\n                <form method="get" action="/dashboard" data-persist-filters="dashboard">\n                    {\'<label>Buyer<select name="buyer">\' + buyer_options + \'</select></label>\' if is_admin_role(user) or user.get("role") == "operator" else \'\'}\n                    <label>Manager<select name="manager">{manager_options}</select></label>\n                    <label>Geo<select name="geo">{geo_options}</select></label>\n                    <label>Offer<select name="offer">{offer_options}</select></label>\n                    <label>View<select name="period_view">{period_view_options}</select></label>\n                    <label>Period<select name="period_label">{period_options}</select></label>\n                    <label>Search<input type="text" name="search" value="{escape(search)}"></label>\n                    <button type="submit" class="btn small-btn">Filter</button>\n                    <a href="/dashboard" class="ghost-btn small-btn" data-reset-filters="dashboard">Reset</a>\n                </form>\n            </div>\n        </div>\n    </div>\n\n    {render_statistic_cards(totals)}\n\n    {render_statistic_dashboard(rows)}\n\n    {render_dashboard_overview(overview)}\n    \'\'\'\n\n    top_actions = f\'<a class="small-btn" href="{export_link}">⬇ CSV</a>\' if is_admin_role(user) else ""\n    return page_shell("Dashboard", content, "dashboard", top_actions=top_actions, current_user=user)\n\ndef show_hierarchy(\n    request: Request,\n    buyer: str = Query(default=""),\n    manager: str = Query(default=""),\n    geo: str = Query(default=""),\n    offer: str = Query(default=""),\n    search: str = Query(default=""),\n    period_view: str = Query(default="all"),\n    period_label: str = Query(default=""),\n):\n    return render_dashboard_page(request, buyer, manager, geo, offer, search, period_view, period_label)\n\ndef show_dashboard(\n    request: Request,\n    buyer: str = Query(default=""),\n    manager: str = Query(default=""),\n    geo: str = Query(default=""),\n    offer: str = Query(default=""),\n    search: str = Query(default=""),\n    period_view: str = Query(default="all"),\n    period_label: str = Query(default=""),\n):\n    return render_dashboard_page(request, buyer, manager, geo, offer, search, period_view, period_label)\n\n'


def bind_domain_routes(ctx):
    scope = dict(ctx)
    exec(MODULE_SOURCE, scope)
    return {name: scope[name] for name in TARGET_FUNCTIONS}
